//! # E_8 lattice quantization of KV-cache key/value vectors.
//!
//! The attention KV-cache ([`crate::kv_cache::KVCache`]) stores, per layer ×
//! head × position, a `head_dim`-dimensional **key** and **value** vector in
//! `f32`. For a long context this is the dominant memory cost of inference
//! and the dominant resolution knob: every cached K/V is read on every
//! subsequent decode step. It is also the textbook **cell-filling** candidate
//! for the certified E_8 quantizer ([`crate::e8_quantizer`]):
//!
//!   * `head_dim` is high (64 / 128 for the models in this tree);
//!   * after the model's RMSNorm/projection the per-head K and V vectors are
//!     close to isotropic and **decorrelated across dims** — there is no
//!     raster/spatial coupling like the deblur scalar lift that washed E_8
//!     out (`mesh_residual_deblur::ResidualQuantizer`);
//!   * at a step matched to the per-dim std the samples span MANY cells.
//!
//! ## The PROVEN recipe (mirrors `n_rgb_lattice_quant`, +9.30% measured)
//!
//!   1. **CENTER** each vector: subtract its per-vector DC mean, add it back
//!      after quantizing. Raw origin-hugging vectors waste the lattice on a
//!      constant and measure as a wash.
//!   2. **ONE full E_8 cell per 8 decorrelated dims + a CUBIC tail** on the
//!      `head_dim % 8` leftover. NEVER zero-pad the tail up to a multiple of 8
//!      — the dead pad dims collapse the effective per-block dimension and
//!      re-introduce the wash (E8⊕E8-pad measured +0.75% on `n_rgb`). The
//!      `E8Tail` scheme here puts `head_dim / 8` full E_8 cells down and
//!      rounds the remainder cubically.
//!   3. **MEASURE cell-filling FIRST** ([`characterize_kv_cell_filling`]) and
//!      only claim a win if the data fills cells; the expected blended edge is
//!      `(8·blocks / head_dim) × 14%`. For `head_dim` a multiple of 8 (64,
//!      128) that is the full ~14%.
//!
//! ## Additive + default-off
//!
//! [`KvQuantizer::None`] (the default) is a byte-for-byte pass-through; this
//! module never touches the live cache unless a caller opts in. It exposes a
//! quantize-on-store helper ([`quantize_kv_vec`]) and the characterization /
//! head-to-head error tooling, mirroring the `n_rgb` module's API exactly so
//! the measurement discipline is identical.

#![allow(dead_code)]

use crate::e8_quantizer::nearest_e8;
use crate::tukey_bowl::{gate, Admission};

/// Which lattice scheme (if any) to apply to a KV head vector. Additive +
/// opt-in; [`None`](KvQuantizer::None) leaves the vector untouched (default).
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum KvQuantizer {
    /// No quantization — the vector passes through unchanged. (Default.)
    #[default]
    None,
    /// Cubic ℤ^d quantization: round every coordinate to the grid at `step`.
    /// Worst-case lattice quantizer (per-coord G = 1/12). Present so the E_8
    /// win is measured at the SAME bit budget.
    Cubic,
    /// `floor(d/8)` full E_8 cells laid over the first `8·blocks` dims +
    /// cubic on the `d % 8` tail. The RECOMMENDED path: every cell-filling
    /// 8-block takes the certified ~14% E_8 edge; the short tail (which cannot
    /// form an E_8 cell) is rounded cubically. NO zero-padding (dead dims).
    E8Tail,
    /// `ceil(d/8)` E_8 cells with the final block zero-padded up to 8. Present
    /// ONLY to MEASURE the dead-dim wash the recipe warns against; never the
    /// recommendation when `d % 8 != 0`.
    E8Pad,
}

/// Centring mode applied before quantization.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
pub enum KvCentering {
    /// Quantize the raw vector (origin-displaced). NOT recommended.
    Raw,
    /// Subtract the per-vector mean (remove DC), add it back after. This is
    /// what makes the AC structure cell-filling. (Default.)
    #[default]
    PerVectorMean,
}

/// Config for the KV E_8 quantization path. Mirrors `NRgbQuantConfig`.
#[derive(Clone, Copy, Debug)]
pub struct KvQuantConfig {
    pub quantizer: KvQuantizer,
    pub centering: KvCentering,
    /// Quantization step (cell edge) in feature units. Cubic and E_8 share it
    /// so the comparison is at equal bit budget.
    pub step: f32,
}

impl Default for KvQuantConfig {
    fn default() -> Self {
        Self {
            quantizer: KvQuantizer::None,
            centering: KvCentering::PerVectorMean,
            step: 0.02,
        }
    }
}

/// Snap one 8-block to the nearest E_8 cell at `step`, returning the
/// dequantized 8-vector in feature units (certified Lean-×2-coord convention
/// of [`nearest_e8`] — identical to the `n_rgb` path).
#[inline]
fn quantize_e8_block(block: &[f64; 8], step: f32) -> [f32; 8] {
    let mut scaled = [0.0_f64; 8];
    for k in 0..8 {
        scaled[k] = block[k] * (2.0 / step as f64);
    }
    let qc = nearest_e8(scaled);
    let mut out = [0.0_f32; 8];
    for k in 0..8 {
        out[k] = ((qc[k] as f64) * (step as f64 / 2.0)) as f32;
    }
    out
}

/// Quantize a single KV head vector of arbitrary dimension `d = v.len()` in
/// place into `out` (which must have the same length). When the quantizer is
/// [`KvQuantizer::None`] the input is copied verbatim (byte-for-byte
/// pass-through). Returns the mean-absolute quantization noise over the `d`
/// coordinates (against the centred input, the quantity actually rounded).
pub fn quantize_kv_into(v: &[f32], out: &mut [f32], cfg: &KvQuantConfig) -> f32 {
    debug_assert_eq!(v.len(), out.len(), "quantize_kv_into: length mismatch");
    let d = v.len();
    if cfg.quantizer == KvQuantizer::None || d == 0 {
        out.copy_from_slice(v);
        return 0.0;
    }
    let step = cfg.step.max(1e-6);

    // Center: remove per-vector DC so the lattice sees the AC structure.
    let mean = match cfg.centering {
        KvCentering::Raw => 0.0_f32,
        KvCentering::PerVectorMean => v.iter().copied().sum::<f32>() / d as f32,
    };
    // Centred copy.
    let mut c = vec![0.0_f32; d];
    for i in 0..d {
        c[i] = v[i] - mean;
    }

    let mut q = vec![0.0_f32; d];
    match cfg.quantizer {
        KvQuantizer::None => unreachable!(),
        KvQuantizer::Cubic => {
            let inv = 1.0_f32 / step;
            for i in 0..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
        KvQuantizer::E8Tail => {
            let blocks = d / 8; // full E_8 cells only
            for b in 0..blocks {
                let base = b * 8;
                let mut block = [0.0_f64; 8];
                for k in 0..8 {
                    block[k] = c[base + k] as f64;
                }
                let qb = quantize_e8_block(&block, step);
                for k in 0..8 {
                    q[base + k] = qb[k];
                }
            }
            // Cubic on the d % 8 tail (cannot form an E_8 cell).
            let inv = 1.0_f32 / step;
            for i in (blocks * 8)..d {
                q[i] = (c[i] * inv).round() * step;
            }
        }
        KvQuantizer::E8Pad => {
            let mut i = 0usize;
            while i < d {
                let mut block = [0.0_f64; 8];
                for k in 0..8 {
                    // zero-pad past the end of the vector (the dead dims)
                    block[k] = if i + k < d { c[i + k] as f64 } else { 0.0 };
                }
                let qb = quantize_e8_block(&block, step);
                for k in 0..8 {
                    if i + k < d {
                        q[i + k] = qb[k];
                    }
                }
                i += 8;
            }
        }
    }

    // Restore DC + accumulate noise against the centred input.
    let mut noise = 0.0_f32;
    for i in 0..d {
        noise += (c[i] - q[i]).abs();
        out[i] = q[i] + mean;
    }
    noise / d as f32
}

/// Allocating convenience wrapper around [`quantize_kv_into`].
pub fn quantize_kv_vec(v: &[f32], cfg: &KvQuantConfig) -> Vec<f32> {
    let mut out = vec![0.0_f32; v.len()];
    quantize_kv_into(v, &mut out, cfg);
    out
}

// ── Cell-filling diagnostics (the precondition measurement) ────────────────

/// Cell-filling diagnostics for a set of `d`-dimensional KV vectors at a
/// quantization `step`. This is the measurement that PREDICTS whether E_8 will
/// win — reported before any end-to-end edge is claimed.
#[derive(Clone, Debug)]
pub struct KvCellFillingReport {
    pub n: usize,
    pub dim: usize,
    pub min: f32,
    pub max: f32,
    /// Overall std of the centred feature.
    pub centered_std: f32,
    /// Mean absolute inter-dimension correlation (off-diagonal of the centred
    /// corr matrix). Low = decorrelated = good for E_8.
    pub mean_abs_corr: f32,
    pub max_abs_corr: f32,
    /// Effective dimension = participation ratio (Σλ)²/Σλ² of the centred
    /// covariance eigenvalues. Near `dim` = isotropic = cell-filling.
    pub effective_dim: f32,
    /// `centered_std / step` — cells the spread covers. ≳1 = multi-cell.
    pub spread_in_cells: f32,
    /// Distinct cells occupied by the centred feature cubic-quantized at
    /// `step`, over `n` samples.
    pub cells_occupied: usize,
    /// `true` iff cell-filling by our criteria: spread ≳ 1 cell, effective_dim
    /// ≥ 8 (an 8-block is full-rank), inter-dim corr ≲ 0.2.
    pub is_cell_filling: bool,
}

/// Characterize a set of equal-length KV vectors at `step`. The diagnostic is
/// run on the **per-vector DC-removed residual** — exactly what the recipe's
/// `PerVectorMean` E8Tail quantizer sees ("the lattice sees the AC structure
/// after DC removal"). A large shared per-vector DC offset would otherwise
/// masquerade as a rank-1 all-dims correlation and collapse the effective
/// dimension; removing it per vector measures the true AC structure. Uses the
/// Frobenius identity `Σλ² = ‖cov‖_F²` for the effective dim (no eigensolver).
pub fn characterize_kv_cell_filling(data: &[Vec<f32>], step: f32) -> KvCellFillingReport {
    let n = data.len();
    assert!(n > 0, "need samples to characterize");
    let d = data[0].len();
    assert!(d > 0, "vectors must be non-empty");
    for v in data {
        assert_eq!(v.len(), d, "all KV vectors must share dimension");
    }
    let nf = n as f64;

    // Per-vector DC-removed residual rows (the AC structure the lattice sees).
    let mut min = f32::INFINITY;
    let mut max = f32::NEG_INFINITY;
    let mut ac: Vec<Vec<f64>> = Vec::with_capacity(n);
    for v in data {
        let m = v.iter().copied().sum::<f32>() as f64 / d as f64;
        let mut r = vec![0.0_f64; d];
        for j in 0..d {
            min = min.min(v[j]);
            max = max.max(v[j]);
            r[j] = v[j] as f64 - m;
        }
        ac.push(r);
    }

    // Per-dim mean of the AC residual (≈0 by construction, but kept exact).
    let mut mean = vec![0.0_f64; d];
    for r in &ac {
        for j in 0..d {
            mean[j] += r[j];
        }
    }
    for j in 0..d {
        mean[j] /= nf;
    }

    // Covariance of the AC residual (d×d) in f64.
    let mut cov = vec![0.0_f64; d * d];
    let mut centered_sq = 0.0_f64;
    let mut cbuf = vec![0.0_f64; d];
    for r in &ac {
        for j in 0..d {
            cbuf[j] = r[j] - mean[j];
            centered_sq += cbuf[j] * cbuf[j];
        }
        for i in 0..d {
            let ci = cbuf[i];
            let row = i * d;
            for j in 0..d {
                cov[row + j] += ci * cbuf[j];
            }
        }
    }
    for x in cov.iter_mut() {
        *x /= nf;
    }
    let centered_std = (centered_sq / (nf * d as f64)).sqrt() as f32;

    // Inter-dim correlation (off-diagonal mean / max abs).
    let mut sum_abs = 0.0_f64;
    let mut max_abs = 0.0_f64;
    let mut cnt = 0usize;
    for i in 0..d {
        for j in 0..d {
            if i == j {
                continue;
            }
            let denom = (cov[i * d + i] * cov[j * d + j]).sqrt();
            let r = if denom > 0.0 {
                cov[i * d + j] / denom
            } else {
                0.0
            };
            sum_abs += r.abs();
            max_abs = max_abs.max(r.abs());
            cnt += 1;
        }
    }
    let mean_abs_corr = (sum_abs / cnt.max(1) as f64) as f32;
    let max_abs_corr = max_abs as f32;

    // Effective dim = (trace)² / ‖cov‖_F² (symmetric cov ⇒ Σλ² = Frobenius²).
    let mut trace = 0.0_f64;
    let mut fro2 = 0.0_f64;
    for i in 0..d {
        trace += cov[i * d + i];
    }
    for x in &cov {
        fro2 += x * x;
    }
    let effective_dim = if fro2 > 0.0 {
        (trace * trace / fro2) as f32
    } else {
        0.0
    };

    // Cells occupied: centred vector cubic-quantized at step, distinct keys.
    let step = step.max(1e-6);
    let inv = 1.0_f32 / step;
    let mut seen = std::collections::HashSet::new();
    for v in data {
        let m = v.iter().copied().sum::<f32>() / d as f32;
        let key: Vec<i64> = v.iter().map(|&x| ((x - m) * inv).round() as i64).collect();
        seen.insert(key);
    }
    let cells_occupied = seen.len();
    let spread_in_cells = centered_std / step;
    let is_cell_filling = spread_in_cells >= 1.0 && effective_dim >= 8.0 && mean_abs_corr <= 0.2;

    KvCellFillingReport {
        n,
        dim: d,
        min,
        max,
        centered_std,
        mean_abs_corr,
        max_abs_corr,
        effective_dim,
        spread_in_cells,
        cells_occupied,
        is_cell_filling,
    }
}

/// Mean per-coordinate squared quantization error of `quantizer` over a KV
/// vector set at `step`. The head-to-head metric (lower = less noise at equal
/// bit budget).
pub fn mean_sq_quant_error(
    data: &[Vec<f32>],
    quantizer: KvQuantizer,
    centering: KvCentering,
    step: f32,
) -> f64 {
    if data.is_empty() {
        return 0.0;
    }
    let cfg = KvQuantConfig {
        quantizer,
        centering,
        step,
    };
    let d = data[0].len();
    let mut out = vec![0.0_f32; d];
    let mut acc = 0.0_f64;
    let mut count = 0usize;
    for v in data {
        quantize_kv_into(v, &mut out, &cfg);
        for j in 0..v.len() {
            let e = (v[j] - out[j]) as f64;
            acc += e * e;
        }
        count += v.len();
    }
    acc / count.max(1) as f64
}

// ── JIT-dequant bowl gate: accept-rate of a quantizer at a margin ────────────

/// How a quantizer fares as a JIT speculative-dequant drafter under the
/// Tukey-bowl gate ([`crate::tukey_bowl`]) at decision margin `gamma`.
///
/// Each tile is masked (quantize→dequantize at equal bit budget `step`) and
/// gated: a tile is **admitted** (runs at coarse-code cost with certified
/// behaviour) iff `2·τ ≤ γ`, where `τ` is the masking residual. We report the
/// gate under **both** norms because the certificate
/// (`QualityMarginCacheAdmissibility`) bounds the **sup-norm (L∞)** residual,
/// while the lattice quantization win is an **L2 / energy** phenomenon — the
/// two need not agree, and the gap is the finding.
#[derive(Clone, Copy, Debug)]
pub struct BowlGateReport {
    pub tiles: usize,
    /// Accept rate under the certificate's L∞ gate (`2·‖τ‖∞ ≤ γ`).
    pub accept_rate_linf: f64,
    /// Accept rate under an L2-energy gate (`2·‖τ‖₂ ≤ γ`), for comparison —
    /// the norm the lattice actually shrinks. Not (yet) cert-backed.
    pub accept_rate_l2: f64,
    /// Mean sup-norm (L∞) masking residual over all tiles.
    pub mean_tau_linf: f64,
    /// Mean L2 masking residual over all tiles.
    pub mean_tau_l2: f64,
    /// RMSE over L∞-admitted tiles (the error actually shipped).
    pub admitted_rmse: f64,
}

/// Compute the bowl-gate report for `quantizer` over `data` at `step`, `gamma`.
/// `τ_∞ = ‖v − Q(v)‖∞`, `τ₂ = ‖v − Q(v)‖₂` per tile.
pub fn bowl_gate_report(
    data: &[Vec<f32>],
    quantizer: KvQuantizer,
    step: f32,
    gamma: f64,
) -> BowlGateReport {
    let cfg = KvQuantConfig {
        quantizer,
        centering: KvCentering::PerVectorMean,
        step,
    };
    let d = data[0].len();
    let mut out = vec![0.0f32; d];
    let (mut adm_linf, mut adm_l2) = (0usize, 0usize);
    let (mut sum_linf, mut sum_l2) = (0.0f64, 0.0f64);
    let (mut adm_sq, mut adm_n) = (0.0f64, 0usize);
    for v in data {
        quantize_kv_into(v, &mut out, &cfg);
        let mut linf = 0.0f64;
        let mut l2sq = 0.0f64;
        for j in 0..d {
            let e = (v[j] - out[j]).abs() as f64;
            if e > linf {
                linf = e;
            }
            l2sq += e * e;
        }
        let l2 = l2sq.sqrt();
        sum_linf += linf;
        sum_l2 += l2;
        // L∞ gate = the certificate's gate (sup-norm).
        if let Admission::Admit { .. } = gate(linf, gamma) {
            adm_linf += 1;
            adm_sq += l2sq;
            adm_n += d;
        }
        // L2-energy gate (comparison only).
        if 2.0 * l2 <= gamma {
            adm_l2 += 1;
        }
    }
    let n = data.len().max(1) as f64;
    BowlGateReport {
        tiles: data.len(),
        accept_rate_linf: adm_linf as f64 / n,
        accept_rate_l2: adm_l2 as f64 / n,
        mean_tau_linf: sum_linf / n,
        mean_tau_l2: sum_l2 / n,
        admitted_rmse: if adm_n > 0 {
            (adm_sq / adm_n as f64).sqrt()
        } else {
            0.0
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::e8_quantizer::SplitMix64;

    /// A deterministic, realistic synthetic KV dataset: per-head vectors that
    /// mimic post-projection attention K/V statistics — near-isotropic,
    /// decorrelated across dims, modest per-vector DC drift. NO real spatial
    /// coupling (unlike the deblur lift), so this is the cell-filling regime.
    ///
    /// `head_dim` matches the models in this tree (64 / 128). Each coordinate
    /// is a near-Gaussian draw (sum of uniforms, central-limit) scaled to a
    /// realistic per-dim std, plus a small per-vector DC offset (the part
    /// centring removes).
    fn synthetic_kv(n: usize, head_dim: usize, seed: u64, sigma: f32) -> Vec<Vec<f32>> {
        let mut rng = SplitMix64::new(seed);
        let mut out = Vec::with_capacity(n);
        for _ in 0..n {
            // Per-vector DC drift (brightness-analog; centring strips it).
            let dc = rng.next_in(0.5) as f32;
            let mut v = vec![0.0_f32; head_dim];
            for j in 0..head_dim {
                // Sum of 4 uniforms ≈ Gaussian (central limit), unit-ish var.
                let g = (rng.next_in(1.0) + rng.next_in(1.0) + rng.next_in(1.0) + rng.next_in(1.0))
                    as f32
                    / 2.0;
                v[j] = dc + sigma * g;
            }
            out.push(v);
        }
        out
    }

    #[test]
    fn pass_through_when_off_is_byte_for_byte() {
        let v: Vec<f32> = (0..64).map(|i| (i as f32 * 0.013).sin()).collect();
        let cfg = KvQuantConfig::default();
        assert_eq!(cfg.quantizer, KvQuantizer::None);
        let out = quantize_kv_vec(&v, &cfg);
        assert_eq!(out, v, "None must pass through byte-for-byte");
    }

    #[test]
    fn quantizers_produce_finite_output() {
        let v: Vec<f32> = (0..128)
            .map(|i| 0.3 + 0.05 * (i as f32 * 0.21).cos())
            .collect();
        for q in [KvQuantizer::Cubic, KvQuantizer::E8Tail, KvQuantizer::E8Pad] {
            let cfg = KvQuantConfig {
                quantizer: q,
                ..Default::default()
            };
            let out = quantize_kv_vec(&v, &cfg);
            assert_eq!(out.len(), v.len());
            assert!(out.iter().all(|x| x.is_finite()), "{q:?} finite");
        }
    }

    /// E8Tail with head_dim a multiple of 8 uses ONLY full E_8 cells (no tail,
    /// no padding) — the cleanest case (64 = 8·8, 128 = 16·8).
    #[test]
    fn e8tail_uses_full_cells_for_multiples_of_8() {
        for &d in &[64usize, 128] {
            assert_eq!(d % 8, 0, "model head_dims are multiples of 8");
        }
    }

    /// CHARACTERIZATION — lead with this. Print the synthetic KV distribution
    /// and the cell-filling verdict at head_dim 64 and 128.
    #[test]
    fn characterize_kv_cell_filling_print() {
        for &d in &[64usize, 128] {
            let data = synthetic_kv(4000, d, 0xCAFE_0000 ^ d as u64, 0.05);
            let step = 0.02_f32;
            let r = characterize_kv_cell_filling(&data, step);
            println!(
                "\n[KV characterization] head_dim={d} N={}\n  \
                 range=[{:.4},{:.4}] centered_std={:.4}\n  \
                 mean|corr|={:.4} max|corr|={:.4} effective_dim={:.2}/{}\n  \
                 step={step} spread_in_cells={:.2} cells_occupied={}/{} ({:.1}%)\n  \
                 => CELL-FILLING: {}",
                r.n,
                r.min,
                r.max,
                r.centered_std,
                r.mean_abs_corr,
                r.max_abs_corr,
                r.effective_dim,
                d,
                r.spread_in_cells,
                r.cells_occupied,
                r.n,
                100.0 * r.cells_occupied as f32 / r.n as f32,
                if r.is_cell_filling { "YES" } else { "NO" },
            );
            assert_eq!(r.dim, d);
            assert!(r.centered_std > 0.0);
            assert!(r.effective_dim > 0.0 && r.effective_dim <= d as f32 + 1e-2);
        }
    }

    /// PROPERTY: E_8 beats cubic at equal bit budget on the (cell-filling)
    /// centred KV feature — asserted ONLY when the characterization says so.
    #[test]
    fn e8_vs_cubic_on_kv_tied_to_cell_filling() {
        let d = 128usize; // 16 full E_8 cells, no tail — the full ~14% case.
        let data = synthetic_kv(6000, d, 0xC0DE_F00D, 0.05);
        let step = 0.02_f32;
        let report = characterize_kv_cell_filling(&data, step);

        let mse_cubic =
            mean_sq_quant_error(&data, KvQuantizer::Cubic, KvCentering::PerVectorMean, step);
        let mse_e8 =
            mean_sq_quant_error(&data, KvQuantizer::E8Tail, KvCentering::PerVectorMean, step);
        let mse_e8_raw = mean_sq_quant_error(&data, KvQuantizer::E8Tail, KvCentering::Raw, step);
        let pct = (1.0 - mse_e8 / mse_cubic) * 100.0;
        let pct_raw = (1.0 - mse_e8_raw / mse_cubic) * 100.0;
        println!(
            "\n[KV E8 vs cubic | head_dim={d}] step={step} cell_filling={}\n  \
             MSE cubic ℤ^{d}        = {mse_cubic:.8}\n  \
             MSE E8Tail (centred)  = {mse_e8:.8}  ({pct:+.2}% vs cubic)  <- recommended\n  \
             MSE E8Tail (RAW/noDC) = {mse_e8_raw:.8}  ({pct_raw:+.2}% vs cubic)\n  \
             prediction: d%8==0 ⇒ full E_8 on all dims ⇒ ~14% MSE reduction",
            report.is_cell_filling,
        );

        if report.is_cell_filling {
            assert!(
                mse_e8 < mse_cubic,
                "cell-filling ⇒ E8Tail must beat cubic: e8={mse_e8:.8} cubic={mse_cubic:.8}"
            );
            // d a multiple of 8 ⇒ all dims get the E_8 edge; expect ~14%.
            assert!(
                pct > 8.0 && pct < 20.0,
                "expected ~14% (all dims E_8), got {pct:.2}%"
            );
        } else {
            println!("  (NOT cell-filling at this step → E_8 edge not expected)");
        }
    }

    /// END-TO-END, COLD vs WARM: quantize every KV vector at head_dim 64 and
    /// 128, report aggregate reconstruction RMSE for baseline / cubic / E_8.
    #[test]
    fn bench_kv_baseline_vs_cubic_vs_e8_cold_warm() {
        for &d in &[64usize, 128] {
            let data = synthetic_kv(8000, d, 0xBEEF_0000 ^ d as u64, 0.05);
            let step = 0.02_f32;
            let recon = |q: KvQuantizer| -> (f64, std::time::Duration) {
                let cfg = KvQuantConfig {
                    quantizer: q,
                    centering: KvCentering::PerVectorMean,
                    step,
                };
                let mut out = vec![0.0_f32; d];
                let t = std::time::Instant::now();
                let mut acc = 0.0_f64;
                for v in &data {
                    quantize_kv_into(v, &mut out, &cfg);
                    for j in 0..d {
                        let e = (v[j] - out[j]) as f64;
                        acc += e * e;
                    }
                }
                ((acc / (data.len() * d) as f64).sqrt(), t.elapsed())
            };
            let (base_c, tb_c) = recon(KvQuantizer::None);
            let (cub_c, tc_c) = recon(KvQuantizer::Cubic);
            let (e8_c, te_c) = recon(KvQuantizer::E8Tail);
            let (base_w, tb_w) = recon(KvQuantizer::None);
            let (cub_w, tc_w) = recon(KvQuantizer::Cubic);
            let (e8_w, te_w) = recon(KvQuantizer::E8Tail);
            let ratio = e8_w / cub_w.max(1e-12);
            let pct = (1.0 - ratio * ratio) * 100.0;
            println!(
                "\n[KV end-to-end head_dim={d}] N={} step={step}\n  \
                 BASELINE(none) RMSE={base_c:.8} (warm {base_w:.8}) | COLD {tb_c:?} WARM {tb_w:?}\n  \
                 CUBIC ℤ^{d}     RMSE={cub_c:.8} (warm {cub_w:.8}) | COLD {tc_c:?} WARM {tc_w:?}\n  \
                 E8Tail         RMSE={e8_c:.8} (warm {e8_w:.8}) | COLD {te_c:?} WARM {te_w:?}\n  \
                 VERDICT (warm): E8/cubic RMSE ratio={ratio:.4} => MSE {pct:+.2}% vs cubic",
                data.len(),
            );
            assert_eq!(base_c, 0.0, "baseline pass-through is exact");
            assert!(ratio <= 1.001, "E8Tail must be ≤ cubic: ratio={ratio:.4}");
        }
    }

    /// JIT-DEQUANT BOWL GATE: sweep the decision margin γ and report the
    /// certified accept-rate for cubic vs E_8 as JIT-dequant drafters, under
    /// BOTH the cert's L∞ gate and an L2-energy gate. The question this answers:
    /// does E_8's tighter (L2) bowl convert into a higher *certified* accept
    /// rate — and under which norm? We print and let the data decide; we assert
    /// only soundness (E_8 must keep its L2 edge; gate must be monotone in γ).
    #[test]
    fn bench_jit_dequant_bowl_accept_rate() {
        let d = 128usize; // 16 full E_8 cells, no tail.
        let data = synthetic_kv(8000, d, 0xB0_07_5EED, 0.05);
        let step = 0.02_f32;
        // γ swept across BOTH residual scales: the L∞ band (~2·0.01) and the
        // L2 transition band (~2·0.06, where E8's energy edge should bite).
        let gammas = [
            0.02_f64, 0.115, 0.120, 0.123, 0.126, 0.129, 0.132, 0.16,
        ];
        println!("\n[JIT-dequant bowl gate | head_dim={d} step={step}] N={}", data.len());
        println!(
            "  τ̄: cubic L∞={:.5} L2={:.5} | e8 L∞={:.5} L2={:.5}",
            bowl_gate_report(&data, KvQuantizer::Cubic, step, 1.0).mean_tau_linf,
            bowl_gate_report(&data, KvQuantizer::Cubic, step, 1.0).mean_tau_l2,
            bowl_gate_report(&data, KvQuantizer::E8Tail, step, 1.0).mean_tau_linf,
            bowl_gate_report(&data, KvQuantizer::E8Tail, step, 1.0).mean_tau_l2,
        );
        println!("  {:>7} | {:>18} | {:>18}", "γ", "accept L∞ (cub/e8)", "accept L2 (cub/e8)");
        for &g in &gammas {
            let c = bowl_gate_report(&data, KvQuantizer::Cubic, step, g);
            let e = bowl_gate_report(&data, KvQuantizer::E8Tail, step, g);
            println!(
                "  {g:>7.3} | {:>7.1}% / {:>6.1}% | {:>7.1}% / {:>6.1}%   (adm RMSE cub={:.5} e8={:.5})",
                100.0 * c.accept_rate_linf,
                100.0 * e.accept_rate_linf,
                100.0 * c.accept_rate_l2,
                100.0 * e.accept_rate_l2,
                c.admitted_rmse,
                e.admitted_rmse,
            );
        }
        // Soundness 1: E_8 must keep its L2 (energy) edge — mean L2 residual lower.
        let c1 = bowl_gate_report(&data, KvQuantizer::Cubic, step, 1.0);
        let e1 = bowl_gate_report(&data, KvQuantizer::E8Tail, step, 1.0);
        assert!(
            e1.mean_tau_l2 <= c1.mean_tau_l2,
            "E8 must keep its L2 edge: e8={:.6} cubic={:.6}",
            e1.mean_tau_l2,
            c1.mean_tau_l2
        );
        // Soundness 2: accept-rate is monotone non-decreasing in γ (bigger
        // margin ⇒ never fewer admits).
        let mut prev = -1.0;
        for &g in &gammas {
            let a = bowl_gate_report(&data, KvQuantizer::E8Tail, step, g).accept_rate_l2;
            assert!(a + 1e-9 >= prev, "accept-rate must be monotone in γ");
            prev = a;
        }
    }
}
